#include <stdio.h>
#include <pthread.h>

int counter = 0;
pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;

void *increment(void *arg) {
    int id = *(int *)arg;
    for (int i = 0; i < 3; i++) {
        pthread_mutex_lock(&lock);
        counter++;
        printf("Thread %d: counter = %d\n", id, counter);
        pthread_mutex_unlock(&lock);
    }
    return NULL;
}

int main(void) {
    pthread_t t[3];
    int ids[3] = {0, 1, 2};
    for (int i = 0; i < 3; i++) {
        pthread_create(&t[i], NULL, increment, &ids[i]);
        pthread_join(t[i], NULL);
    }
    printf("Final: %d\n", counter);
    return 0;
}

